sql.if:
AND EXISTS ( SELECT 1 FROM ( SELECT MAX(LCTR_WKNO) AS CURR_WKNO FROM TB_LMS_LCTR_WKNO_SCHDL WHERE SBJCT_ID = #{sbjctId} AND NVL(DELYN, 'N') = 'N' AND LCTR_WKNO_SYMD IS NOT NULL AND LCTR_WKNO_SYMD <> '00000000' AND LCTR_WKNO_SYMD <= TO_CHAR(SYSDATE, 'YYYYMMDD') ) CW JOIN TB_LMS_LCTR_WKNO_SCHDL S_F ON S_F.SBJCT_ID = #{sbjctId} AND NVL(S_F.DELYN, 'N') = 'N' AND S_F.LCTR_WKNO < CW.CURR_WKNO LEFT JOIN WK_USER_LRN_STS W_F ON W_F.USER_ID = U.USER_ID AND W_F.SBJCT_ID = #{sbjctId} AND W_F.WKNO = S_F.LCTR_WKNO LEFT JOIN PRGRT_TO_STS C_F ON C_F.SBJCT_ID = #{sbjctId} WHERE 1 = 1
AND S_F.LCTR_WKNO >= #{absnWknoFrom}
AND S_F.LCTR_WKNO <= #{absnWknoTo}
AND CASE WHEN W_F.WKNO IS NULL THEN 1 WHEN NVL(W_F.LRN_STS_ORD, 0) IN (2, 3) THEN 0 WHEN NVL(W_F.LRN_STS_ORD, 0) = 1 THEN 1 WHEN W_F.LRN_PRGRT >= NVL(C_F.ATND_MIN_PRGRT, 80) THEN 0 WHEN W_F.LRN_PRGRT >= NVL(C_F.LATE_MIN_PRGRT, 60) THEN 0 ELSE 1 END = 1 )

mapper.sql:
WHERE 1 = 1

    AND U.ORG_ID = #{orgId}


    AND U.USER_ID = #{userId}


    AND (
    LOWER(U.USERNM) LIKE FN_LIKE_VAL(LOWER(#{keyword}))
    OR U.STDNT_NO LIKE FN_LIKE_VAL(#{keyword})
    OR LOWER(D.DEPTNM) LIKE FN_LIKE_VAL(LOWER(#{keyword}))
    )

mapper.select:
SELECT COUNT(*) FROM TB_LMS_SBJCT A LEFT JOIN TB_LMS_USER B ON A.PROF_ID = B.USER_ID LEFT JOIN TB_LMS_DEPT D ON A.DEPT_ID = D.DEPT_ID WHERE NVL(A.DELYN,'N') = 'N' AND A.SBJCT_YR = #{searchYr} AND TRIM(A.SBJCT_SMSTR) IN (#{searchSmstr}, LPAD(#{searchSmstr}, 2, '0')) AND (B.ORG_ID = #{orgId} OR B.ORG_ID IS NULL)
AND A.UNIV_GBNCD = #{univGbn}
AND A.DEPT_ID = #{deptId}
AND A.SBJCT_ID = #{sbjctId}
AND ( A.SBJCTNM LIKE '%' || #{searchKeyword} || '%' OR A.CRCLMN_NO LIKE '%' || #{searchKeyword} || '%' OR D.DEPTNM LIKE '%' || #{searchKeyword} || '%' OR B.USERNM LIKE '%' || #{searchKeyword} || '%' )

SELECT A.SBJCT_ID AS sbjctId , A.SBJCTNM AS sbjctnm , A.CRCLMN_NO AS crclmnNo , A.DVCLAS_NO AS dvclasNo FROM TB_LMS_SBJCT A LEFT JOIN TB_LMS_USER B ON A.PROF_ID = B.USER_ID WHERE NVL(A.DELYN,'N') = 'N' AND A.SBJCT_YR = #{searchYr} AND TRIM(A.SBJCT_SMSTR) IN (#{searchSmstr}, LPAD(#{searchSmstr}, 2, '0')) AND (B.ORG_ID = #{orgId} OR B.ORG_ID IS NULL)
AND A.UNIV_GBNCD = #{univGbn}
AND A.DEPT_ID = #{deptId}
ORDER BY A.SBJCTNM ASC, A.DVCLAS_NO ASC

SELECT * FROM ( SELECT ROWNUM AS rnum, X.* FROM ( SELECT ROW_NUMBER() OVER( ORDER BY A.SBJCT_YR DESC, TRIM(A.SBJCT_SMSTR) DESC, A.SBJCTNM ASC ) AS lineNo , A.SBJCT_ID AS sbjctId , A.SBJCT_YR AS sbjctYr , TRIM(A.SBJCT_SMSTR) AS sbjctSmstr , A.DEPT_ID AS deptId , D.DEPTNM AS deptnm , A.CRCLMN_NO AS crclmnNo , A.SBJCTNM AS sbjctnm , A.DVCLAS_NO AS dvclasNo , A.DVCLAS_NCKNM AS dvclasNcknm , A.CRDTS AS crdts , B.USERNM AS profNm -- 담당교수 , ( SELECT LISTAGG(U2.USERNM, ', ') WITHIN GROUP (ORDER BY SA.SBJCT_ADM_SEQNO) FROM TB_LMS_SBJCT_ADM SA JOIN TB_LMS_USER U2 ON U2.USER_ID = SA.USER_ID WHERE SA.SBJCT_ID = A.SBJCT_ID AND SA.SBJCT_ADM_TYCD = 'PROF' ) AS coProfNm -- 공동교수 , ( SELECT LISTAGG(U2.USERNM, ', ') WITHIN GROUP (ORDER BY SA.SBJCT_ADM_SEQNO) FROM TB_LMS_SBJCT_ADM SA JOIN TB_LMS_USER U2 ON U2.USER_ID = SA.USER_ID WHERE SA.SBJCT_ID = A.SBJCT_ID AND SA.SBJCT_ADM_TYCD = 'TUT' ) AS tutor -- 튜터 , ( SELECT LISTAGG(U2.USERNM, ', ') WITHIN GROUP (ORDER BY SA.SBJCT_ADM_SEQNO) FROM TB_LMS_SBJCT_ADM SA JOIN TB_LMS_USER U2 ON U2.USER_ID = SA.USER_ID WHERE SA.SBJCT_ID = A.SBJCT_ID AND SA.SBJCT_ADM_TYCD = 'ASST' ) AS asst -- 조교 , O.ORGNM AS orgNm , A.SMSTR_CHRT_ID AS smstrChrtId , A.USEYN AS useyn FROM TB_LMS_SBJCT A LEFT JOIN TB_LMS_USER B ON A.PROF_ID = B.USER_ID LEFT JOIN TB_LMS_DEPT D ON A.DEPT_ID = D.DEPT_ID LEFT JOIN TB_LMS_ORG O ON O.ORG_ID = B.ORG_ID WHERE NVL(A.DELYN,'N') = 'N' AND A.SBJCT_YR = #{searchYr} AND TRIM(A.SBJCT_SMSTR) IN (#{searchSmstr}, LPAD(#{searchSmstr}, 2, '0')) AND (B.ORG_ID = #{orgId} OR B.ORG_ID IS NULL)
AND A.UNIV_GBNCD = #{univGbn}
AND A.DEPT_ID = #{deptId}
AND A.SBJCT_ID = #{sbjctId}
AND ( A.SBJCTNM LIKE '%' || #{searchKeyword} || '%' OR A.CRCLMN_NO LIKE '%' || #{searchKeyword} || '%' OR D.DEPTNM LIKE '%' || #{searchKeyword} || '%' OR B.USERNM LIKE '%' || #{searchKeyword} || '%' )
) X WHERE ROWNUM <= (#{firstIndex} + #{listScale}) ) WHERE rnum > #{firstIndex}

SELECT COUNT(*)
FROM TB_LMS_LOG_USER_ACTV L
WHERE L.SBJCT_ID = #{sbjctId}
AND L.USER_ID = #{userId}
AND EXISTS (
SELECT 1 FROM TB_LMS_ATNDLC A
WHERE A.USER_ID  = L.USER_ID
AND A.SBJCT_ID = #{sbjctId}
)

    AND L.USER_REQ_CTS LIKE '%' || #{keyword} || '%'

SELECT * FROM ( SELECT ROWNUM AS rnum, X.* FROM ( SELECT ROW_NUMBER() OVER(ORDER BY L.ACTV_DTTM DESC) AS lineNo , TO_CHAR(L.ACTV_DTTM,'YYYY.MM.DD HH24:MI:SS') AS actDttm , L.USER_REQ_CTS AS actConts , NVL(L.CNTN_BRWSR, L.REQ_TYCD) AS deviceNm , L.CNTN_IP AS ipAddr FROM TB_LMS_LOG_USER_ACTV L WHERE L.SBJCT_ID = #{sbjctId} AND L.USER_ID = #{userId} AND EXISTS ( SELECT 1 FROM TB_LMS_ATNDLC A WHERE A.USER_ID = L.USER_ID AND A.SBJCT_ID = #{sbjctId} )
AND L.USER_REQ_CTS LIKE '%' || #{keyword} || '%'
ORDER BY L.ACTV_DTTM DESC ) X WHERE ROWNUM <= (#{firstIndex} + #{listScale}) ) WHERE rnum > #{firstIndex}

mapper.update:
UPDATE TB_LMS_BYWK_USER_LRN_STS
SET BFR_LRN_STSCD = LRN_STSCD
  , LRN_STSCD     = 'ATND'
  , MDFR_ID       = #{mdfrId}
  , MOD_DTTM      = TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS')
WHERE USER_ID            = #{userId}
  AND LCTR_WKNO_SCHDL_ID = #{lctrWknoSchdlId}

UPDATE TB_LMS_BYWK_USER_LRN_STS
SET LRN_STSCD     = NVL(BFR_LRN_STSCD,'ABSNT')
  , BFR_LRN_STSCD = NULL
  , MDFR_ID       = #{mdfrId}
  , MOD_DTTM      = TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS')
WHERE USER_ID            = #{userId}
  AND LCTR_WKNO_SCHDL_ID = #{lctrWknoSchdlId}

mapper.select:
SELECT COUNT(1)
FROM TB_LMS_ATNDLC A
JOIN TB_LMS_USER U
ON U.USER_ID = A.USER_ID
WHERE A.SBJCT_ID = #{sbjctId}
AND A.USER_ID  = #{userId}

    AND U.ORG_ID = #{orgId}

SELECT COUNT(1)
FROM TB_LMS_LCTR_WKNO_SCHDL W
WHERE W.SBJCT_ID = #{sbjctId}
AND W.LCTR_WKNO = #{wkNo}
AND NVL(W.DELYN, 'N') = 'N'

    AND W.LCTR_WKNO_SCHDL_ID = #{lctrWknoSchdlId}
